defmodule DevopsAutomation.CommandService do
  @moduledoc """
  A safe command execution service that only allows pre-approved commands.
  NEVER pass raw user input to System.cmd with "sh -c".
  """

  # Allowlist of permitted commands with their expected argument patterns
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "uptime" => {"/usr/bin/uptime", []},
    "list_processes" => {"/bin/ps", ["aux"]},
    "check_port" => {"/usr/bin/ss", ["-tlnp"]},
    "docker_ps" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}\t{{.Ports}}"]},
    "docker_stats" => {"/usr/bin/docker", ["stats", "--no-stream"]},
    "systemd_status" => {"/usr/bin/systemctl", ["status"]},
    "ping" => {"/usr/bin/ping", ["-c", "4"]}
  }

  @doc """
  Executes a pre-approved command by its alias name.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, extra_args \\ []) when is_binary(command_name) and is_list(extra_args) do
    case Map.get(@allowed_commands, command_name) do
      nil ->
        {:error, :command_not_allowed}

      {executable, base_args} ->
        sanitized_args = sanitize_args(extra_args)

        case sanitized_args do
          {:error, reason} ->
            {:error, reason}

          {:ok, safe_args} ->
            args = base_args ++ safe_args
            run_command(executable, args)
        end
    end
  end

  def list_available_commands do
    Map.keys(@allowed_commands)
  end

  defp run_command(executable, args) do
    try do
      case System.cmd(executable, args,
             stderr_to_stdout: true,
             timeout: 30_000,
             env: [{"PATH", "/usr/bin:/bin"}]
           ) do
        {output, 0} ->
          {:ok, %{output: output, exit_code: 0}}

        {output, exit_code} ->
          {:error, %{output: output, exit_code: exit_code}}
      end
    rescue
      e in ErlangError ->
        {:error, %{message: "Command execution failed: #{inspect(e)}"}}
    end
  end

  # Sanitize extra arguments - reject anything that looks like shell injection
  defp sanitize_args(args) do
    dangerous_patterns = ~r/[;&|`$(){}\\!<>'"#\n\r]/

    if Enum.all?(args, fn arg ->
         is_binary(arg) &&
           !Regex.match?(dangerous_patterns, arg) &&
           String.length(arg) < 256
       end) do
