defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  def index(conn, _params) do
    commands = CommandService.list_available_commands()
    json(conn, %{available_commands: commands})
  end

  def execute(conn, %{"command" => command_name} = params) do
    extra_args = Map.get(params, "args", [])

    extra_args =
      if is_list(extra_args), do: extra_args, else: []

    case CommandService.execute(command_name, extra_args) do
      {:ok, result} ->
        conn
        |> put_status(:ok)
        |> json(%{
          status: "success",
          command: command_name,
          output: result.output,
          exit_code: result.exit_code
        })

      {:error, :command_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{
          status: "error",
          message: "Command '#{command_name}' is not in the allowlist",
          available_commands: CommandService.list_available_commands()
        })

      {:error, :dangerous_argument_detected} ->
        conn
        |> put_status(:bad_request)
        |> json(%{
          status: "error",
          message: "Arguments contain disallowed characters"
        })

      {:error, result} when is_map(result) ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{
          status: "error",
          output: Map.get(result, :output, ""),
          exit_code: Map.get(result, :exit_code),
          message: Map.get(result, :message, "Command failed")
        })
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{status: "error", message: "Missing required 'command' parameter"})
  end
